  real r = 4*tan(t)/cos(t);
  return (r*cos(t), r*sin(t));
}

path foo = moo(0);
real t;

for (t = 0; t <= 1.2; t = t + 0.1) {
  foo = foo--moo(t);
}

draw(foo,red);
draw(reflect((0,0),(0,1))*(foo),red);

draw((-12,0)--(12,0));
draw((0,-5)--(0,30));
label("$r = 4 \tan \theta \sec \theta$", (22,15), red);
