\begin{align*}
&\begin{pmatrix} 3a^2 - 3 & 3a \\ 2a^2 - a - 2 & 2a - 1 \end{pmatrix} \begin{pmatrix} -1 & -3a - 2 \\ a & 3a^2 + 2a - 3 \end{pmatrix} \\
&= \begin{pmatrix} (3a^2 - 1)(-1) + (3a)(a) & (3a^2 - 3)(-3a - 2) + (3a)(3a^2 + 2a - 3) \\ (2a^2 - a - 2)(-1) + (2a - 1)(a) & (2a^2 - a - 2)(-3a - 2) + (2a - 1)(3a^2 + 2a - 3) \end{pmatrix} \\
